{
  "learning_outcomes": [
    {
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry",
      "topic": "Foundational understanding of matter, measurement, and stoichiometry.",
      "outcomes": [
        "Explain the importance of chemistry in various disciplines.",
        "Distinguish between different types of matter and their properties.",
        "Apply principles of uncertainty and significant figures in measurements.",
        "Utilize laws of chemical combination to predict reaction outcomes.",
        "Calculate atomic and molecular masses using Dalton's theory.",
        "Perform mole concept calculations and determine molar masses.",
        "Compute percentage composition from chemical formulas.",
        "Execute stoichiometric calculations for reactants and products."
      ]
    },
    {
      "unit_name": "Structure of Atom",
      "chapter_name": "Structure of Atom",
      "topic": "Understanding the evolution and models of atomic structure.",
      "outcomes": [
        "Trace the discovery history of sub-atomic particles.",
        "Compare historical atomic models with modern quantum mechanical concepts.",
        "Analyze developments leading to Bohr's model for hydrogen.",
        "Apply Bohr's theory to explain spectral lines of hydrogen.",
        "Describe the transition from classical mechanics to quantum mechanical models."
      ]
    },
    {
      "unit_name": "Organic Chemistry: Some basic Principles and Techniques",
      "chapter_name": "Some basic Principles and Techniques",
      "topic": "Fundamentals of organic structure, nomenclature, and mechanisms.",
      "outcomes": [
        "Represent structures using various notations including bond-line formulas."
      ]
    },
    {
      "unit_name": "Hydrocarbons",
      "chapter_name": "Hydrocarbons",
      "topic": "Classification and properties of aliphatic and aromatic hydrocarbons.",
      "outcomes": [
        "Distinguish between alkanes, alkenes, alkynes, and aromatics."
      ]
    },
    {
      "unit_name": "Chemical Bonding and Molecular Structure",
      "chapter_name": "Chemical Bonding and Molecular Structure",
      "topic": "Theories of chemical bonding and molecular geometry.",
      "outcomes": [
        "Apply Kossel-Lewis approach to predict bond formation."
      ]
    },
    {
      "unit_name": "Chemical Thermodynamics",
      "chapter_name": "Chemical Thermodynamics",
      "topic": "Energy changes in chemical processes.",
      "outcomes": [
        "Define thermodynamic terms including enthalpy, entropy, and Gibbs energy."
      ]
    },
    {
      "unit_name": "Equilibrium",
      "chapter_name": "Equilibrium",
      "topic": "Dynamic equilibrium in physical and chemical processes.",
      "outcomes": [
        "Apply the law of mass action to calculate equilibrium constants."
      ]
    },
    {
      "unit_name": "Redox Reactions",
      "chapter_name": "Redox Reactions",
      "topic": "Oxidation-reduction processes and electrode potentials.",
      "outcomes": [
        "Identify oxidation numbers in complex molecules."
      ]
    },
    {
      "unit_name": "Classification of Elements and Periodicity in Properties",
      "chapter_name": "Classification of Elements and Periodicity in Properties",
      "topic": "Periodic trends and electronic configurations.",
      "outcomes": [
        "Explain the genesis of periodic classification."
      ]
    },
    {
      "unit_name": "E. Quantitative Estimation",
      "chapter_name": "E. Quantitative Estimation",
      "topic": "Volumetric analysis techniques.",
      "outcomes": [
        "Prepare standard solutions of oxalic acid and sodium carbonate."
      ]
    },
    {
      "unit_name": "F. Qualitative Analysis",
      "chapter_name": "F. Qualitative Analysis",
      "topic": "Detection of elements in organic compounds.",
      "outcomes": [
        "Detect nitrogen, sulphur, and chlorine in organic samples."
      ]
    },
    {
      "unit_name": "PROJECTS",
      "chapter_name": "PROJECTS",
      "topic": "Scientific investigation and data analysis.",
      "outcomes": [
        "Design and execute a scientific project involving laboratory testing."
      ]
    }
  ]
}
